#!/usr/bin/env node
// Generated by OrchestKit Claude Plugin
// Created: 2026-07-23

// =============================================================================
// stamp-whats-new.mjs — regenerate the README "What's New" block from CHANGELOG
// =============================================================================
// The README count spans (<!--ork:skills--> …) are kept current by
// scripts/stamp-counts.sh, but "What's New" was hand-written prose with no
// generator and rotted ~68 minor versions behind (stuck at v8.16.0 while the
// project shipped v8.84.x). This makes it a derived view of CHANGELOG.md, which
// release-please keeps authoritative, so it can never drift again.
//
// It rewrites the content between <!--ork:whats-new--> and <!--/ork--> in
// README.md with the top N release entries from CHANGELOG.md.
//
// Usage:
//   node scripts/stamp-whats-new.mjs            # rewrite the block
//   node scripts/stamp-whats-new.mjs --check    # exit 1 if the block is stale
//
// Env:
//   WHATS_NEW_COUNT    number of releases to show (default 8)
//   WHATS_NEW_BULLETS  max bullets per release before "+N more" (default 5)
// =============================================================================

import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const CHANGELOG = join(ROOT, "CHANGELOG.md");
const README = join(ROOT, "README.md");

const N = Number(process.env.WHATS_NEW_COUNT || 8);
const MAX_BULLETS = Number(process.env.WHATS_NEW_BULLETS || 5);
const START = "<!--ork:whats-new-->";
const END = "<!--/ork-->";

// ── Parse CHANGELOG into release blocks ─────────────────────────────────────

/** @returns {{version:string,url:string,date:string,bullets:string[]}[]} */
function parseChangelog(text) {
  const lines = text.split("\n");
  // A release header: ## [8.84.5](compare-url) (2026-07-22)
  const header = /^## \[(\d+\.\d+\.\d+)\]\((.*?)\) \((\d{4}-\d{2}-\d{2})\)\s*$/;
  const blocks = [];
  let cur = null;
  for (const line of lines) {
    const m = line.match(header);
    if (m) {
      if (cur) blocks.push(cur);
      cur = { version: m[1], url: m[2], date: m[3], bullets: [] };
      continue;
    }
    if (!cur) continue;
    // Bullets are "* …"; sub-section headers (### Features) are skipped so the
    // block stays scannable — the "**scope:**" prefix already conveys the type.
    if (/^\s*[*-]\s+/.test(line)) cur.bullets.push(cleanBullet(line));
  }
  if (cur) blocks.push(cur);
  return blocks;
}

/** Strip release-please link soup: drop the commit link, shorten the issue link. */
function cleanBullet(line) {
  return line
    .replace(/^\s*[*-]\s+/, "")
    .replace(/\s*\(\[[0-9a-f]{7,40}\]\([^)]*\)\)/g, "") // ([f0f9557](url))
    .replace(/\(\[#(\d+)\]\([^)]*\)\)/g, "(#$1)") // ([#3056](url)) -> (#3056)
    .trim();
}

// ── Render the block ────────────────────────────────────────────────────────

function render(blocks) {
  const shown = blocks.slice(0, N);
  const out = [
    "<!-- AUTO-GENERATED from CHANGELOG.md by scripts/stamp-whats-new.mjs — do not hand-edit between the ork:whats-new markers. -->",
    "<!-- Regenerated on `npm run build`; CI (`--check`) fails if this is stale. Full history: [CHANGELOG.md](CHANGELOG.md). -->",
    "",
  ];
  for (const b of shown) {
    out.push(`**[v${b.version}](${b.url})** · ${b.date}`);
    out.push("");
    if (b.bullets.length === 0) {
      out.push("- Maintenance release — see the changelog for details.");
    } else {
      const head = b.bullets.slice(0, MAX_BULLETS);
      for (const bl of head) out.push(`- ${bl}`);
      const extra = b.bullets.length - head.length;
      if (extra > 0) out.push(`- …and ${extra} more (see [CHANGELOG.md](CHANGELOG.md))`);
    }
    out.push("");
  }
  out.push("_See [CHANGELOG.md](CHANGELOG.md) for the full release history._");
  return out.join("\n");
}

// ── Splice between markers ──────────────────────────────────────────────────

function splice(readme, inner) {
  const s = readme.indexOf(START);
  // END (<!--/ork-->) is shared with the count spans, so match the one that
  // closes THIS block: the first END after START, not the global first.
  const e = s === -1 ? -1 : readme.indexOf(END, s + START.length);
  if (s === -1 || e === -1) {
    throw new Error(
      `README.md is missing the ${START} … ${END} markers. Add them in the "What's New" section first.`,
    );
  }
  return readme.slice(0, s + START.length) + "\n" + inner + "\n" + readme.slice(e);
}

// ── Main ────────────────────────────────────────────────────────────────────

const check = process.argv.includes("--check");
const blocks = parseChangelog(readFileSync(CHANGELOG, "utf8"));
if (blocks.length === 0) {
  console.error("stamp-whats-new: no release blocks parsed from CHANGELOG.md");
  process.exit(1);
}
const readme = readFileSync(README, "utf8");
const next = splice(readme, render(blocks));

if (check) {
  if (next !== readme) {
    console.error(
      "STALE: README 'What's New' is out of date with CHANGELOG.md.\n" +
        "Run 'node scripts/stamp-whats-new.mjs' (or 'npm run build') to fix.",
    );
    process.exit(1);
  }
  console.log(`What's New up to date (top ${Math.min(N, blocks.length)} of ${blocks.length} releases).`);
  process.exit(0);
}

writeFileSync(README, next);
console.log(`Stamped What's New: top ${Math.min(N, blocks.length)} of ${blocks.length} releases (through v${blocks[0].version}).`);
